import React, { useState, useRef, useEffect } from 'react';
import { useMutation } from 'convex/react';
import { api } from '../convex/_generated/api';

// ── Custom Select ─────────────────────────────────────────────────────────────
const CustomSelect = ({ value, onChange, options, placeholder }) => {
    const [open, setOpen] = useState(false);
    const ref = useRef(null);
    const selected = options.find(o => o.value === value);

    useEffect(() => {
        const handler = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
        document.addEventListener('mousedown', handler);
        return () => document.removeEventListener('mousedown', handler);
    }, []);

    return (
        <div ref={ref} className='relative'>
            <button
                type='button'
                onClick={() => setOpen(!open)}
                className={`w-full px-4 py-3.5 bg-slate-50 border rounded-xl flex items-center justify-between transition-all outline-none font-medium
                    ${open ? 'border-brand-blue ring-2 ring-brand-blue/20 bg-white' : 'border-slate-200 hover:border-slate-300'}
                    ${value ? 'text-slate-800' : 'text-slate-400'}`}
            >
                <span>{selected ? selected.label : placeholder}</span>
                <svg className={`w-5 h-5 text-slate-400 transition-transform duration-200 flex-shrink-0 ${open ? 'rotate-180 text-brand-blue' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" />
                </svg>
            </button>
            {open && (
                <div className='absolute z-50 w-full mt-1.5 bg-white border border-slate-200 rounded-xl shadow-xl overflow-hidden animate-in slide-in-from-top-2 duration-150'>
                    {options.map((opt) => (
                        <button
                            key={opt.value}
                            type='button'
                            onClick={() => { onChange(opt.value); setOpen(false); }}
                            className={`w-full text-left px-4 py-3 text-sm font-medium transition-colors flex items-center justify-between
                                ${value === opt.value
                                    ? 'bg-brand-blue/5 text-brand-blue font-bold'
                                    : 'text-slate-700 hover:bg-slate-50'}`}
                        >
                            {opt.label}
                            {value === opt.value && (
                                <svg className="w-4 h-4 text-brand-blue" fill="currentColor" viewBox="0 0 20 20">
                                    <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                                </svg>
                            )}
                        </button>
                    ))}
                </div>
            )}
        </div>
    );
};

// ── Step Indicator ────────────────────────────────────────────────────────────
const StepIndicator = ({ current, total, labels }) => (
    <div className='flex items-center justify-center mb-8'>
        {Array.from({ length: total }).map((_, i) => {
            const step = i + 1;
            const done = step < current;
            const active = step === current;
            return (
                <React.Fragment key={step}>
                    <div className='flex flex-col items-center gap-1'>
                        <div className={`flex items-center justify-center w-9 h-9 rounded-full font-black text-sm transition-all duration-300
                            ${done ? 'bg-emerald-500 text-white shadow-md shadow-emerald-200'
                                : active ? 'bg-brand-blue text-white shadow-md shadow-brand-blue/30 scale-110'
                                    : 'bg-slate-100 text-slate-400'}`}>
                            {done ? (
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M5 13l4 4L19 7" />
                                </svg>
                            ) : step}
                        </div>
                        <span className={`text-[10px] font-bold uppercase tracking-wide hidden sm:block ${active ? 'text-brand-blue' : done ? 'text-emerald-500' : 'text-slate-300'}`}>
                            {labels[i]}
                        </span>
                    </div>
                    {step < total && (
                        <div className={`h-0.5 flex-1 mx-2 mb-4 rounded-full transition-all duration-500 ${done ? 'bg-emerald-400' : 'bg-slate-200'}`} />
                    )}
                </React.Fragment>
            );
        })}
    </div>
);

// ── Success Screen ────────────────────────────────────────────────────────────
const SuccessScreen = ({ name, examNumber }) => (
    <div className='flex flex-col items-center justify-center text-center py-10 px-4 animate-in fade-in slide-in-from-bottom-4 duration-500'>
        <div className='w-20 h-20 bg-emerald-100 rounded-full flex items-center justify-center mb-6 shadow-lg shadow-emerald-100'>
            <svg className="w-10 h-10 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M5 13l4 4L19 7" />
            </svg>
        </div>
        <h3 className='text-2xl md:text-3xl font-black text-slate-800 mb-2'>You're Registered! 🎉</h3>
        <p className='text-slate-500 font-medium mb-8 max-w-xs'>
            <span className='text-brand-blue font-bold'>{name}</span>, your De-Legacy Mock 2025 registration is confirmed.
        </p>
        <div className='w-full bg-slate-50 border border-slate-200 rounded-2xl p-5 mb-6'>
            <p className='text-xs font-bold uppercase tracking-widest text-slate-400 mb-2'>Your Exam Number</p>
            <p className='font-mono text-2xl font-black text-brand-blue tracking-widest'>{examNumber}</p>
        </div>
        <p className='text-xs text-slate-400 font-medium'>Keep your exam number safe — you'll need it on exam day.</p>
    </div>
);

// ── Input field helper ────────────────────────────────────────────────────────
const inputCls = 'w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-brand-blue/30 focus:border-brand-blue focus:bg-white transition-all outline-none text-slate-800 font-medium placeholder-slate-400';

// ── Main Form ─────────────────────────────────────────────────────────────────
const Form = () => {
    const [step, setStep] = useState(1);
    const [submitted, setSubmitted] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [dupError, setDupError] = useState('');

    // Step 1
    const [name, setName] = useState('');
    const [gender, setGender] = useState('');
    const [email, setEmail] = useState('');
    const [phone, setPhone] = useState('');

    // Step 2
    const [department, setDepartment] = useState('');
    const [course, setCourse] = useState('');
    const [selectedSubjects, setSelectedSubjects] = useState([]);
    const [showSubjects, setShowSubjects] = useState(false);

    // Step 3
    const [examNumber, setExamNumber] = useState('');
    const [terms, setTerms] = useState(false);

    const registerUser = useMutation(api.users.registerUser);

    const subjects = [
        'Mathematics', 'Physics', 'Chemistry', 'Biology',
        'Geography', 'Economics', 'Accounts', 'CRS',
        'History', 'IRS', 'Government', 'Literature'
    ];

    const genderOptions = [
        { value: 'male', label: 'Male' },
        { value: 'female', label: 'Female' },
        { value: 'other', label: 'Prefer not to say' },
    ];
    const deptOptions = [
        { value: 'science', label: 'Science' },
        { value: 'commerce', label: 'Commercial' },
        { value: 'arts', label: 'Arts' },
        { value: 'others', label: 'Others' },
    ];
    const examOptions = [
        { value: 'UTME', label: 'UTME' },
        { value: 'WAEC', label: 'WAEC' },
        { value: 'De-Legacy MOCK Exam', label: 'De-Legacy MOCK Exam' },
        { value: 'other', label: 'Others' },
    ];

    const handleSubjectChange = (subject) => {
        if (selectedSubjects.includes(subject)) {
            setSelectedSubjects(selectedSubjects.filter(s => s !== subject));
        } else if (selectedSubjects.length < 3) {
            setSelectedSubjects([...selectedSubjects, subject]);
        }
    };

    const generateExamNumber = () => {
        if (name.trim()) {
            const prefix = name.trim().substring(0, 5).toUpperCase().replace(/\s+/g, '');
            setExamNumber(`MOCK-${prefix}-${Math.floor(1000 + Math.random() * 9000)}`);
        }
    };

    const step1Valid = name.trim() && gender && email.trim() && phone.trim();
    const step2Valid = department && course && selectedSubjects.length === 3;
    const step3Valid = examNumber && terms;

    const nextStep = () => { setDupError(''); setStep(s => s + 1); };
    const prevStep = () => { setDupError(''); setStep(s => s - 1); };

    const collectDate = async (e) => {
        e.preventDefault();
        setDupError('');
        setIsSubmitting(true);
        try {
            await registerUser({
                name, email, phone, department, gender, course, examNumber,
                selectedSubjects: ['English', ...selectedSubjects],
            });
            localStorage.setItem('user', JSON.stringify({ name, email, phone, examNumber }));
            setSubmitted(true);
        } catch (error) {
            const msg = error?.message ?? '';
            if (msg.includes('EMAIL_EXISTS')) {
                setDupError('This email is already registered. Please use a different email.');
            } else if (msg.includes('PHONE_EXISTS')) {
                setDupError('This phone number is already registered. Please use a different number.');
            } else {
                setDupError('Something went wrong. Please try again.');
            }
        } finally {
            setIsSubmitting(false);
        }
    };

    const stepLabels = ['Personal', 'Academic', 'Final'];

    return (
        <div className='w-full max-w-xl mx-auto bg-white rounded-3xl shadow-2xl overflow-visible border border-slate-100 relative z-10'>
            {/* Header */}
            <div className='bg-gradient-to-br from-brand-blue to-brand-blue-dark p-6 md:p-8 text-center relative overflow-hidden rounded-t-3xl'>
                <div className='absolute inset-0 bg-black/10 z-0' />
                <div className='absolute -top-10 -right-10 w-40 h-40 bg-white/10 rounded-full blur-2xl' />
                <div className='absolute -bottom-10 -left-10 w-40 h-40 bg-brand-orange/30 rounded-full blur-2xl' />
                <h2 className='relative z-10 text-2xl md:text-4xl font-black text-white mb-1 tracking-tight'>
                    De-Legacy Mock <span className='text-brand-orange'>2025</span>
                </h2>
                <p className='relative z-10 text-blue-100 text-sm max-w-sm mx-auto'>
                    {submitted ? 'Registration Complete' : `Step ${step} of 3 — ${stepLabels[step - 1]}`}
                </p>
            </div>

            {/* Body */}
            <div className='p-5 md:p-8'>
                {submitted ? (
                    <SuccessScreen name={name} examNumber={examNumber} />
                ) : (
                    <>
                        <StepIndicator current={step} total={3} labels={stepLabels} />

                        {/* ── STEP 1 ── */}
                        {step === 1 && (
                            <div className='space-y-4 animate-in fade-in duration-300'>
                                <div>
                                    <label className='block text-sm font-bold text-slate-700 mb-1.5'>Full Student Name</label>
                                    <input type='text' className={inputCls} placeholder='E.g. John Doe' value={name} onChange={e => setName(e.target.value)} />
                                </div>
                                <div>
                                    <label className='block text-sm font-bold text-slate-700 mb-1.5'>Gender</label>
                                    <CustomSelect value={gender} onChange={setGender} options={genderOptions} placeholder='Select Gender' />
                                </div>
                                <div>
                                    <label className='block text-sm font-bold text-slate-700 mb-1.5'>Email Address</label>
                                    <input type='email' className={inputCls} placeholder='E.g. john@gmail.com' value={email} onChange={e => setEmail(e.target.value)} />
                                </div>
                                <div>
                                    <label className='block text-sm font-bold text-slate-700 mb-1.5'>Phone Number</label>
                                    <input type='tel' className={inputCls} placeholder='E.g. 08012345678' value={phone} onChange={e => setPhone(e.target.value)} />
                                </div>
                                <button
                                    type='button' onClick={nextStep} disabled={!step1Valid}
                                    className='w-full mt-2 px-4 py-3.5 text-white bg-brand-blue hover:bg-brand-blue-dark disabled:opacity-40 disabled:cursor-not-allowed font-black text-sm md:text-base uppercase tracking-widest rounded-xl shadow-lg shadow-brand-blue/20 transition-all duration-300 flex items-center justify-center gap-2'
                                >
                                    Continue
                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
                                </button>
                            </div>
                        )}

                        {/* ── STEP 2 ── */}
                        {step === 2 && (
                            <div className='space-y-4 animate-in fade-in duration-300'>
                                <div>
                                    <label className='block text-sm font-bold text-slate-700 mb-1.5'>Preferred Department</label>
                                    <CustomSelect value={department} onChange={setDepartment} options={deptOptions} placeholder='Select Department' />
                                </div>
                                <div>
                                    <label className='block text-sm font-bold text-slate-700 mb-1.5'>Examination Type</label>
                                    <CustomSelect value={course} onChange={setCourse} options={examOptions} placeholder='Select Examination' />
                                </div>

                                {/* Subject picker */}
                                <div className='relative'>
                                    <div className='flex justify-between items-center mb-1.5'>
                                        <label className='block text-sm font-bold text-slate-700'>Subject Combination</label>
                                        <span className='text-[10px] uppercase font-bold text-brand-orange bg-orange-50 px-2 py-0.5 rounded-full'>
                                            {selectedSubjects.length}/3
                                        </span>
                                    </div>
                                    <p className='text-xs text-slate-500 mb-2 font-medium'>English is compulsory. Select 3 more.</p>
                                    <button
                                        type='button'
                                        onClick={() => setShowSubjects(!showSubjects)}
                                        className={`w-full px-4 py-3.5 bg-slate-50 border rounded-xl flex items-center justify-between transition-all outline-none
                                            ${showSubjects ? 'border-brand-blue ring-2 ring-brand-blue/20 bg-white' : 'border-slate-200 hover:border-slate-300'}`}
                                    >
                                        <span className={selectedSubjects.length > 0 ? 'text-brand-blue font-bold truncate max-w-[80%] text-sm' : 'text-slate-400 font-medium text-sm'}>
                                            {selectedSubjects.length > 0 ? `English, ${selectedSubjects.join(', ')}` : 'Click to select subjects...'}
                                        </span>
                                        <svg className={`w-5 h-5 text-slate-400 transition-transform duration-200 flex-shrink-0 ${showSubjects ? 'rotate-180 text-brand-blue' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" />
                                        </svg>
                                    </button>
                                    {showSubjects && (
                                        <div className='absolute z-30 w-full mt-1.5 p-3 border border-slate-200 rounded-xl bg-white shadow-2xl top-full left-0 animate-in slide-in-from-top-2 duration-150'>
                                            <div className='flex items-center bg-slate-50 p-3 rounded-lg mb-3'>
                                                <input type='checkbox' checked readOnly className='w-4 h-4 accent-brand-blue mr-2.5 opacity-60 cursor-not-allowed' />
                                                <span className='font-black text-brand-blue text-sm'>English Language <span className='text-xs font-semibold text-slate-400'>(Compulsory)</span></span>
                                            </div>
                                            <div className='grid grid-cols-2 gap-2 max-h-48 overflow-y-auto'>
                                                {subjects.map((subject, i) => {
                                                    const isSelected = selectedSubjects.includes(subject);
                                                    const isDisabled = selectedSubjects.length >= 3 && !isSelected;
                                                    return (
                                                        <label key={i} className={`flex items-center p-2.5 rounded-lg cursor-pointer transition-all border text-sm
                                                            ${isSelected ? 'bg-brand-blue/5 border-brand-blue/30 font-bold text-brand-blue' : 'bg-white border-slate-100 hover:bg-slate-50 text-slate-700 font-medium'}
                                                            ${isDisabled ? 'opacity-40 cursor-not-allowed' : ''}`}>
                                                            <input type='checkbox' className='w-4 h-4 accent-brand-blue mr-2 cursor-pointer' checked={isSelected} onChange={() => handleSubjectChange(subject)} disabled={isDisabled} />
                                                            {subject}
                                                        </label>
                                                    );
                                                })}
                                            </div>
                                        </div>
                                    )}
                                </div>

                                <div className='flex gap-2.5 pt-1'>
                                    <button type='button' onClick={prevStep} className='flex-1 px-4 py-3.5 bg-slate-100 text-slate-700 hover:bg-slate-200 font-bold text-sm rounded-xl transition-all flex items-center justify-center gap-1.5'>
                                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
                                        Back
                                    </button>
                                    <button type='button' onClick={nextStep} disabled={!step2Valid} className='flex-[2] px-4 py-3.5 text-white bg-brand-blue hover:bg-brand-blue-dark disabled:opacity-40 disabled:cursor-not-allowed font-black text-sm uppercase tracking-wider rounded-xl shadow-lg shadow-brand-blue/20 transition-all flex items-center justify-center gap-1.5'>
                                        Continue
                                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
                                    </button>
                                </div>
                            </div>
                        )}

                        {/* ── STEP 3 ── */}
                        {step === 3 && (
                            <form onSubmit={collectDate} className='space-y-4 animate-in fade-in duration-300'>
                                <div>
                                    <label className='block text-sm font-bold text-slate-700 mb-1.5'>Registration Number</label>
                                    <div className='flex gap-2.5'>
                                        <input type='text' className='flex-1 min-w-0 px-4 py-3.5 bg-slate-100 border border-slate-200 font-mono text-slate-700 text-base font-bold tracking-wider rounded-xl outline-none placeholder-slate-400' placeholder='Click Generate →' value={examNumber} readOnly />
                                        <button type='button' onClick={generateExamNumber} className='px-4 py-3.5 bg-slate-800 text-white font-bold text-sm rounded-xl hover:bg-black transition-colors shadow-md whitespace-nowrap flex-shrink-0'>
                                            Generate
                                        </button>
                                    </div>
                                </div>

                                {/* Summary */}
                                <div className='bg-slate-50 rounded-xl border border-slate-200 p-4 text-sm space-y-2'>
                                    <p className='font-black text-slate-400 text-xs uppercase tracking-widest mb-3'>Summary</p>
                                    {[
                                        ['Name', name],
                                        ['Email', email],
                                        ['Phone', phone],
                                        ['Department', department],
                                        ['Exam', course],
                                        ['Subjects', ['English', ...selectedSubjects].join(', ')],
                                    ].map(([label, val]) => (
                                        <div key={label} className='flex justify-between gap-4'>
                                            <span className='text-slate-400 flex-shrink-0'>{label}</span>
                                            <span className='font-bold text-slate-700 text-right truncate'>{val}</span>
                                        </div>
                                    ))}
                                </div>

                                {/* Terms */}
                                <label className='flex items-start gap-3 cursor-pointer bg-slate-50 p-4 rounded-xl border border-slate-100 hover:border-brand-blue/30 transition-colors'>
                                    <div className='flex items-center h-5 mt-0.5 flex-shrink-0'>
                                        <input type='checkbox' className='w-4 h-4 accent-brand-blue rounded cursor-pointer' checked={terms} onChange={() => setTerms(!terms)} required />
                                    </div>
                                    <span className='text-xs text-slate-600 leading-relaxed font-medium'>
                                        I confirm all information is accurate and agree to the <a href='#' className='text-brand-blue font-bold hover:underline'>Terms and Conditions</a> of De-Legacy Academy Registration.
                                    </span>
                                </label>

                                {/* Error */}
                                {dupError && (
                                    <div className='p-3.5 bg-red-50 border border-red-200 text-red-700 rounded-xl flex items-start gap-3 text-sm font-medium'>
                                        <svg className="w-5 h-5 text-red-500 flex-shrink-0 mt-0.5" fill="currentColor" viewBox="0 0 20 20">
                                            <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                                        </svg>
                                        {dupError}
                                    </div>
                                )}

                                <div className='flex gap-2.5 pt-1'>
                                    <button type='button' onClick={prevStep} className='flex-1 px-4 py-3.5 bg-slate-100 text-slate-700 hover:bg-slate-200 font-bold text-sm rounded-xl transition-all flex items-center justify-center gap-1.5'>
                                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
                                        Back
                                    </button>
                                    <button type='submit' disabled={!step3Valid || isSubmitting}
                                        className='flex-[2] px-4 py-3.5 text-white bg-brand-orange hover:bg-brand-orange-dark disabled:opacity-40 disabled:cursor-not-allowed font-black text-sm uppercase tracking-wider rounded-xl shadow-lg shadow-brand-orange/20 hover:-translate-y-0.5 transition-all duration-300 flex items-center justify-center gap-2'>
                                        {isSubmitting ? (
                                            <><svg className="animate-spin w-4 h-4" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" /><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" /></svg>Submitting...</>
                                        ) : (
                                            <>Register <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg></>
                                        )}
                                    </button>
                                </div>
                            </form>
                        )}
                    </>
                )}
            </div>
        </div>
    );
};

export default Form;
