import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

const Navbar = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const location = useLocation();
  const isHomePage = location.pathname === '/';

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Force scrolled state (dark text) if we are not on the homepage hero section
  const navStyle = (isScrolled || !isHomePage) ? 'bg-white/95 backdrop-blur-md shadow-sm py-4' : 'bg-transparent py-5 lg:py-8';
  const textColor = (isScrolled || !isHomePage) ? 'text-brand-blue' : 'text-white';
  const linkColor = (isScrolled || !isHomePage) ? 'text-slate-600' : 'text-white/90';
  const ctaStyle = (isScrolled || !isHomePage)
    ? 'bg-brand-orange text-white hover:bg-brand-orange-light hover:shadow-brand-orange/30'
    : 'bg-white text-brand-blue hover:bg-slate-50 hover:shadow-white/20';

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all md:duration-500 duration-300 ${navStyle}`}>
      <div className='container mx-auto px-4 lg:px-8 flex justify-between items-center'>

        {/* Logo */}
        <Link to='/' className='group flex items-center gap-2'>
          <h1 className={`text-2xl font-black tracking-tight transition-colors duration-300 ${textColor}`}>
            De-Legacy Academy
            <span className='text-brand-orange text-3xl leading-none relative top-1'>.</span>
          </h1>
        </Link>

        {/* Desktop Navigation */}
        <ul className='hidden md:flex items-center space-x-8'>
          <li><Link to='/' className={`font-medium transition-colors duration-300 hover:text-brand-orange ${linkColor}`}>Home</Link></li>
          <li><Link to='/#about' className={`font-medium transition-colors duration-300 hover:text-brand-orange ${linkColor}`}>Mission</Link></li>
          <li><Link to='/register' className={`font-medium transition-colors duration-300 hover:text-brand-orange ${linkColor}`}>Mock Exam</Link></li>
          <li><a href='https://o3schools.com/jamb-free-cbt-app/' target="_blank" rel="noreferrer" className={`font-medium transition-colors duration-300 hover:text-brand-orange ${linkColor}`}>03School JAMB</a></li>
        </ul>

        {/* CTA Button Desktop */}
        <div className='hidden md:block'>
          <Link to='/register' className={`px-7 py-3 text-sm font-bold tracking-wide uppercase rounded-full shadow-lg transition-all duration-300 transform hover:-translate-y-0.5 ${ctaStyle}`}>
            Register Now
          </Link>
        </div>

        {/* Mobile menu button */}
        <button
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
          className={`md:hidden p-2 rounded-lg transition-colors ${(isScrolled || !isHomePage) ? 'text-brand-blue hover:bg-slate-100' : 'text-white hover:bg-white/10'}`}
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            {isMobileMenuOpen ? (
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            ) : (
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
            )}
          </svg>
        </button>
      </div>

      {/* Mobile Menu */}
      <div className={`md:hidden absolute top-full left-0 right-0 bg-white border-t border-slate-100 shadow-2xl transition-all duration-300 origin-top overflow-hidden ${isMobileMenuOpen ? 'max-h-96 border-b' : 'max-h-0'}`}>
        <div className="flex flex-col p-4 space-y-2 bg-white">
          <Link to='/' onClick={() => setIsMobileMenuOpen(false)} className="text-slate-600 font-semibold hover:text-brand-orange px-4 py-3 rounded-lg hover:bg-slate-50 transition-colors">Home</Link>
          <Link to='/#about' onClick={() => setIsMobileMenuOpen(false)} className="text-slate-600 font-semibold hover:text-brand-orange px-4 py-3 rounded-lg hover:bg-slate-50 transition-colors">Mission</Link>
          <Link to='/register' onClick={() => setIsMobileMenuOpen(false)} className="text-slate-600 font-semibold hover:text-brand-orange px-4 py-3 rounded-lg hover:bg-slate-50 transition-colors">Mock Exam</Link>
          <a href='https://03schools.com' target="_blank" rel="noreferrer" className="text-brand-blue font-semibold hover:text-brand-blue-light px-4 py-3 rounded-lg hover:bg-blue-50 transition-colors">03School JAMB App</a>
          <div className="pt-2 pb-2">
            <Link to='/register' onClick={() => setIsMobileMenuOpen(false)} className='block text-center px-6 py-3 bg-brand-orange text-white font-bold rounded-xl shadow-md hover:bg-brand-orange-light transition-colors'>Register Now</Link>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
