import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import Form from '../components/form';
import { useQuery } from 'convex/react';
import { api } from '../convex/_generated/api';

const SESSION_KEY = 'dl_access_granted';

// ── Lock Gate ─────────────────────────────────────────────────────────────────
const AccessGate = ({ onUnlock }) => {
    const [code, setCode] = useState('');
    const [submitted, setSubmitted] = useState(false);
    const [error, setError] = useState('');
    const [checking, setChecking] = useState(false);

    // Only fires when user clicks verify — we pass the entered code to the query
    const result = useQuery(
        api.settings.verifyCode,
        submitted ? { code } : 'skip'
    );

    useEffect(() => {
        if (!submitted) return;
        if (result === undefined) return; // still loading
        setChecking(false);
        if (result?.valid) {
            sessionStorage.setItem(SESSION_KEY, '1');
            onUnlock();
        } else if (result?.reason === 'no_code_set') {
            setError('Registration is not open yet. Please contact the admin.');
            setSubmitted(false);
        } else {
            setError('Incorrect access code. Please try again.');
            setSubmitted(false);
        }
    }, [result, submitted, onUnlock]);

    const handleSubmit = (e) => {
        e.preventDefault();
        if (!code.trim()) return;
        setError('');
        setChecking(true);
        setSubmitted(true);
    };

    return (
        <div className='flex-grow pt-28 pb-20 flex items-center justify-center'>
            <div className='w-full max-w-md mx-auto px-4'>
                <div className='bg-white rounded-3xl shadow-2xl border border-slate-100 overflow-hidden'>
                    {/* Header */}
                    <div className='bg-gradient-to-br from-brand-blue to-brand-blue-dark p-8 text-center relative overflow-hidden'>
                        <div className='absolute inset-0 bg-black/10' />
                        <div className='absolute -top-10 -right-10 w-40 h-40 bg-white/10 rounded-full blur-2xl' />
                        <div className='absolute -bottom-10 -left-10 w-40 h-40 bg-brand-orange/20 rounded-full blur-2xl' />

                        {/* Lock icon */}
                        <div className='relative z-10 w-16 h-16 bg-white/10 backdrop-blur-sm rounded-2xl flex items-center justify-center mx-auto mb-4 border border-white/20'>
                            <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
                            </svg>
                        </div>
                        <h2 className='relative z-10 text-2xl font-black text-white mb-1'>Registration Locked</h2>
                        <p className='relative z-10 text-blue-100 text-sm'>Enter the access code from your admin to proceed.</p>
                    </div>

                    {/* Body */}
                    <form onSubmit={handleSubmit} className='p-6 md:p-8 space-y-5'>
                        <div>
                            <label className='block text-sm font-bold text-slate-700 mb-2'>Access Code</label>
                            <input
                                type='text'
                                value={code}
                                onChange={e => { setCode(e.target.value); setError(''); }}
                                placeholder='Enter your access code...'
                                autoComplete='off'
                                className='w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-brand-blue/30 focus:border-brand-blue focus:bg-white transition-all outline-none text-slate-800 font-mono font-bold tracking-widest text-lg text-center placeholder:font-normal placeholder:tracking-normal placeholder:text-base'
                            />
                        </div>

                        {error && (
                            <div className='flex items-start gap-3 p-3.5 bg-red-50 border border-red-200 text-red-700 rounded-xl text-sm font-medium'>
                                <svg className="w-5 h-5 text-red-500 flex-shrink-0 mt-0.5" fill="currentColor" viewBox="0 0 20 20">
                                    <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                                </svg>
                                {error}
                            </div>
                        )}

                        <button
                            type='submit'
                            disabled={!code.trim() || checking}
                            className='w-full py-3.5 text-white bg-brand-blue hover:bg-brand-blue-dark disabled:opacity-40 disabled:cursor-not-allowed font-black text-sm uppercase tracking-widest rounded-xl shadow-lg shadow-brand-blue/20 transition-all duration-300 flex items-center justify-center gap-2'
                        >
                            {checking ? (
                                <>
                                    <svg className="animate-spin w-4 h-4" fill="none" viewBox="0 0 24 24">
                                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
                                    </svg>
                                    Verifying...
                                </>
                            ) : (
                                <>
                                    Unlock Registration
                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 11V7a4 4 0 118 0m-4 8v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2z" />
                                    </svg>
                                </>
                            )}
                        </button>

                        <div className='text-center'>
                            <Link to='/' className='inline-flex items-center text-sm text-slate-400 hover:text-brand-blue transition-colors font-medium gap-1.5'>
                                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
                                Back to Home
                            </Link>
                        </div>
                    </form>
                </div>

                <p className='text-center text-xs text-slate-400 mt-6 font-medium'>
                    Don't have a code? Contact the admin at De-Legacy Academy.
                </p>
            </div>
        </div>
    );
};

// ── Register Page ─────────────────────────────────────────────────────────────
const Register = () => {
    const [unlocked, setUnlocked] = useState(
        () => sessionStorage.getItem(SESSION_KEY) === '1'
    );

    return (
        <div className='flex flex-col min-h-screen bg-slate-50 font-outfit'>
            <Navbar />

            {unlocked ? (
                <div className='flex-grow pt-28 pb-20'>
                    <div className='container mx-auto px-4 lg:px-8'>
                        {/* Page Header */}
                        <div className='max-w-3xl mx-auto text-center mb-12'>
                            <div className='inline-flex items-center justify-center space-x-2 text-brand-orange font-bold uppercase tracking-widest text-sm mb-4'>
                                <span className='w-8 h-0.5 bg-brand-orange' />
                                <span>Registration Portal</span>
                                <span className='w-8 h-0.5 bg-brand-orange' />
                            </div>
                            <h1 className='text-4xl md:text-5xl lg:text-6xl font-black text-brand-dark mb-6 tracking-tight'>
                                Secure Your Spot For Excellence
                            </h1>
                            <p className='text-lg md:text-xl text-slate-600 font-medium leading-relaxed'>
                                Complete the registration process below to generate your examination number and secure your place in the upcoming De-Legacy Mock Examination.
                            </p>
                        </div>

                        {/* Back Button */}
                        <div className='max-w-xl mx-auto mb-8'>
                            <Link to='/' className='inline-flex items-center text-slate-500 hover:text-brand-blue transition-colors font-bold'>
                                <svg className='w-5 h-5 mr-2' fill='none' stroke='currentColor' viewBox='0 0 24 24'><path strokeLinecap='round' strokeLinejoin='round' strokeWidth='2' d='M10 19l-7-7m0 0l7-7m-7 7h18' /></svg>
                                Back to Home
                            </Link>
                        </div>

                        <Form />
                    </div>
                </div>
            ) : (
                <AccessGate onUnlock={() => setUnlocked(true)} />
            )}

            <Footer />
        </div>
    );
};

export default Register;
